#include <iostream>
#include <cstdio>
using namespace std;
struct Stu{
	int t;
	int m;
}t[1002];
int main(){
    int n;
    cin>>n;
    for(int i=1;i<=n;i++){
    	cin>>t[i].t;
    	t[i].m=i;
	}
    for(int i=1;i<n;i++){
        for(int j=i+1;j<=n;j++){
            if(t[i].t>t[j].t)swap(t[i],t[j]);
        }
    }
    for(int i=1;i<=n;i++){
    	cout<<t[i].m<<' ';
	}
	cout<<endl;
    double sum=0;
    for(int i=1;i<=n;i++){
        sum+=(n-i)*t[i].t*1.0;
    }
    sum/=double(n);
    printf("%.2lf",sum);
    return 0;
}
